import { useEffect, useRef, useState } from "react";
import jsPDF from "jspdf";
import Logo from "./assets/logo-ec_.png";

// ============================================
// CONFIGURACION DE PREMIOS
// ============================================

const initialPrizes = [
   {
    id: 1,
    name: "Refrigerador de 7.2 pies",
    image:
      "data:image/jpeg;base64,",
    price: "Premio #1",
    buttonBg: "bg-green-600",
    buttonHover: "hover:bg-green-700",
    winnerId: null,
  },
  {
    id: 2,
    name: "Estufa Mabe",
    image:
      "data:image/jpeg;base64,",
    price: "Premio #2",
    buttonBg: "bg-red-600",
    buttonHover: "hover:bg-red-700",
    winnerId: null,
  },
 
  {
    id: 3,
    name: "Celular SAMSUNG A25",
    image:
      "data:image/jpeg;base64,",
    price: "Premio #3",
    buttonBg: "bg-yellow-600",
    buttonHover: "hover:bg-yellow-700",
    winnerId: null,
  },
  {
    id: 4,
    name: "Teclado CASIO",
    image:
      "data:image/jpeg;base64,",
    price: "Premio #4",
    buttonBg: "bg-yellow-600",
    buttonHover: "hover:bg-yellow-700",
    winnerId: null,
  },
];

const STORAGE_KEY = "rifa_winners";

// ============================================
// HELPERS localStorage
// ============================================

function loadWinnersFromStorage() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;

    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return null;
    }

    return Object.fromEntries(
      Object.entries(parsed).map(([prizeId, value]) => {
        if (value && typeof value === "object") {
          return [
            prizeId,
            {
              winnerId: value.winnerId ?? null,
              attemptsLeft: value.attemptsLeft ?? 3,
            },
          ];
        }

        return [prizeId, { winnerId: value ?? null, attemptsLeft: 3 }];
      }),
    );
  } catch {
    return null;
  }
}

function saveWinnersToStorage(prizesData) {
  const winners = {};
  prizesData.forEach((p) => {
    winners[p.id] = {
      winnerId: p.winnerId ?? null,
      attemptsLeft: p.attemptsLeft ?? 3,
    };
  });
  localStorage.setItem(STORAGE_KEY, JSON.stringify(winners));
}

function mergeWinnersIntoInitial(initialPrizes) {
  const stored = loadWinnersFromStorage();
  if (!stored) return initialPrizes;

  return initialPrizes.map((p) => ({
    ...p,
    winnerId: stored[p.id]?.winnerId ?? null,
    attemptsLeft: stored[p.id]?.attemptsLeft ?? p.attemptsLeft ?? 3,
  }));
}

// ============================================
// GENERAR PELOTAS
// ============================================

function generateBalls() {
  return Array.from({ length: 350 }).map((_, index) => ({
    id: index,
    number: Math.floor(Math.random() * 99999)
      .toString()
      .padStart(5, "0"),
    left: Math.random() * 100,
    startY: 20 + Math.random() * 80, // posicion inicial Y en vh (no empieza arriba)
    size: 40 + Math.random() * 50,
    duration: 4 + Math.random() * 5,
    delay: Math.random() * 4,
    driftX: (Math.random() - 0.5) * 300, // deriva horizontal aleatoria
    driftY: -(50 + Math.random() * 40), // cuanto sube (negativo = arriba)
    color: [
      "bg-red-500",
      "bg-yellow-400",
      "bg-blue-500",
      "bg-pink-500",
      "bg-green-500",
      "bg-purple-500",
    ][Math.floor(Math.random() * 6)],
  }));
}

// ============================================
// COMPONENTE PRINCIPAL
// ============================================

function App() {
  const [prizesData, setPrizesData] = useState(() =>
    mergeWinnersIntoInitial(initialPrizes),
  );
  const [currentPrizeIndex, setCurrentPrizeIndex] = useState(
    initialPrizes.length - 1,
  );
  const [isLoading, setIsLoading] = useState(false);
  const [animatedWinnerId, setAnimatedWinnerId] = useState("");
  const [showWinnersFloatingList, setShowWinnersFloatingList] = useState(false);
  const [balls, setBalls] = useState([]);
  const [showBalls, setShowBalls] = useState(false); // pelotas solo visibles al sortear
  const [ballsSpeedMultiplier, setBallsSpeedMultiplier] = useState(1.8);

  const currentPrize = prizesData[currentPrizeIndex];

  // Guardar ganadores en localStorage cada vez que cambian
  useEffect(() => {
    saveWinnersToStorage(prizesData);
  }, [prizesData]);

  // ============================================
  // CONFETTI
  // ============================================

  const fireFireworks = () => {
    if (typeof confetti !== "function") return;
    const duration = 5000;
    const end = Date.now() + duration;
    (function frame() {
      confetti({ particleCount: 5, angle: 60, spread: 100, origin: { x: 0 } });
      confetti({ particleCount: 5, angle: 120, spread: 100, origin: { x: 1 } });
      if (Date.now() < end) requestAnimationFrame(frame);
    })();
  };

  // ============================================
  // ASIGNAR GANADOR
  // ============================================

  const assignWinner = async () => {
    setIsLoading(true);
    setBallsSpeedMultiplier(1.8);

    // Generar pelotas frescas y mostrarlas
    setBalls(generateBalls());
    setShowBalls(true);

    try {
      await new Promise((resolve) => setTimeout(resolve, 2500));

      const usedWinnerIds = prizesData.map((p) => p.winnerId).filter(Boolean);

      // Generar un candidato por intento (cada clic consume 1 intento del premio)
      const generated = (Math.floor(Math.random() * 3000) + 1)
        .toString()
        .padStart(5, "0");

      // Si el numero ya fue usado por otro premio, descontar intento y abortar
      if (usedWinnerIds.includes(generated)) {
        setPrizesData((prev) =>
          prev.map((prize) =>
            prize.id === currentPrize.id
              ? { ...prize, attemptsLeft: Math.max((prize.attemptsLeft ?? 3) - 1, 0) }
              : prize,
          ),
        );

        setIsLoading(false);
        setShowBalls(false);
        setAnimatedWinnerId("");
        const remaining = (currentPrize.attemptsLeft ?? 3) - 1;
        if (remaining <= 0) {
          alert("No se pudo asignar un ganador. Intentos agotados para este premio.");
        } else {
          alert(`Número repetido. Intentos restantes: ${remaining}`);
        }
        return;
      }

      // Si es único, animar y asignar; consumir 1 intento
      setBallsSpeedMultiplier(0.1);
      let current = "";
      for (let i = 0; i < generated.length; i++) {
        await new Promise((resolve) => setTimeout(resolve, 4700));
        current += generated[i];
        setAnimatedWinnerId(current);

        setBalls((prev) =>
          prev.map((ball) => ({
            ...ball,
            number: Math.floor(Math.random() * 99999)
              .toString()
              .padStart(5, "0"),
          })),
        );

        if (typeof confetti === "function") {
          confetti({ particleCount: 1000, spread: 300 });
        }
      }

      setPrizesData((prev) =>
        prev.map((prize) =>
          prize.id === currentPrize.id
            ? {
                ...prize,
                winnerId: generated,
                attemptsLeft: Math.max((prize.attemptsLeft ?? 3) - 1, 0),
              }
            : prize,
        ),
      );

      fireFireworks();
      setBallsSpeedMultiplier(1.8);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      // Ocultar pelotas al terminar
      setShowBalls(false);
    }
  };

  // ============================================
  // NAVEGACION
  // ============================================

  const handleNext = () => {
    setAnimatedWinnerId("");
    setCurrentPrizeIndex((prev) =>
      prev === 0 ? prizesData.length - 1 : prev - 1,
    );
  };

  const handlePrevious = () => {
    setAnimatedWinnerId("");
    setCurrentPrizeIndex((prev) =>
      prev === prizesData.length - 1 ? 0 : prev + 1,
    );
  };

  // ============================================
  // RESET
  // ============================================

  const resetAllWinners = () => {
    const reset = prizesData.map((p) => ({ ...p, winnerId: null, attemptsLeft: 3 }));
    setPrizesData(reset);
    setAnimatedWinnerId("");
    localStorage.removeItem(STORAGE_KEY);
  };

  // ============================================
  // PDF
  // ============================================

  const generatePDF = () => {
    const doc = new jsPDF({
      orientation: "portrait",
      unit: "mm",
      format: "a4",
    });
    const pageW = doc.internal.pageSize.getWidth();
    const pageH = doc.internal.pageSize.getHeight();
    const margin = 20;
    const contentW = pageW - margin * 2;

    // ─── HELPERS ────────────────────────────────────────────────
    const hex = (h) => {
      const r = parseInt(h.slice(1, 3), 16);
      const g = parseInt(h.slice(3, 5), 16);
      const b = parseInt(h.slice(5, 7), 16);
      return [r, g, b];
    };

    const setFill = (color) => doc.setFillColor(...hex(color));
    const setDraw = (color) => doc.setDrawColor(...hex(color));
    const setFont = (color) => doc.setTextColor(...hex(color));

    const drawHeader = (pageNumber = 1) => {
      setFill("#1e3a6e");
      doc.rect(0, 0, pageW, 52, "F");

      setFill("#f59e0b");
      doc.rect(0, 52, pageW, 4, "F");

      doc.setFont("helvetica", "bold");
      doc.setFontSize(28);
      setFont("#ffffff");
      doc.text("GRAN RIFA 2026", pageW / 2, 22, { align: "center" });

      doc.setFontSize(13);
      setFont("#fde68a");
      doc.text("Desarrollando la obra misionera", pageW / 2, 31, {
        align: "center",
      });

      doc.setFontSize(10);
      setFont("#cbd5e1");
      doc.setFont("helvetica", "normal");
      doc.text(
        "Ministerios el Calvario  |  PBX: (502) 2246-8080",
        pageW / 2,
        40,
        { align: "center" },
      );

      const fecha = new Date().toLocaleDateString("es-GT", {
        weekday: "long",
        year: "numeric",
        month: "long",
        day: "numeric",
      });
      doc.text(`Fecha de emisión: ${fecha}`, pageW / 2, 47, { align: "center" });

      doc.setFontSize(10);
      setFont("#fef3c7");
      doc.text(`Página ${pageNumber}`, pageW - margin, 16, { align: "right" });
    };

    const drawFooter = () => {
      setFill("#f1f5f9");
      doc.rect(0, pageH - 18, pageW, 18, "F");
      setDraw("#e2e8f0");
      doc.setLineWidth(0.3);
      doc.line(0, pageH - 18, pageW, pageH - 18);

      doc.setFontSize(8);
      doc.setFont("helvetica", "normal");
      setFont("#94a3b8");
      doc.text(
        "Ministerios el Calvario  —  Documento generado automáticamente",
        pageW / 2,
        pageH - 10,
        { align: "center" },
      );
      doc.text(
        `© ${new Date().getFullYear()} Todos los derechos reservados`,
        pageW / 2,
        pageH - 5,
        { align: "center" },
      );
    };

    // ─── CUERPO ─────────────────────────────────────────────────
    let y = 80;
    let currentPage = 1;
    const cardH = 30;
    const summaryH = 24;

    drawHeader(currentPage);

    doc.setFontSize(13);
    doc.setFont("helvetica", "bold");
    setFont("#1e3a6e");
    doc.text("RESULTADOS DEL SORTEO", margin, 70);

    setDraw("#f59e0b");
    doc.setLineWidth(0.8);
    doc.line(margin, 73, pageW - margin, 73);

    // ─── TARJETAS DE PREMIOS ────────────────────────────────────
    prizesData.forEach((prize, index) => {
      const hasWinner = !!prize.winnerId;

      if (y + cardH > pageH - 38) {
        doc.addPage();
        currentPage += 1;
        drawHeader(currentPage);
        y = 80;

        doc.setFontSize(13);
        doc.setFont("helvetica", "bold");
        setFont("#1e3a6e");
        doc.text("RESULTADOS DEL SORTEO", margin, 70);

        setDraw("#f59e0b");
        doc.setLineWidth(0.8);
        doc.line(margin, 73, pageW - margin, 73);
      }

      setFill("#e2e8f0");
      doc.roundedRect(margin + 1, y + 1, contentW, cardH, 4, 4, "F");

      setFill(hasWinner ? "#f0fdf4" : "#fff7ed");
      setDraw(hasWinner ? "#16a34a" : "#d97706");
      doc.setLineWidth(0.5);
      doc.roundedRect(margin, y, contentW, cardH, 4, 4, "FD");

      const bandColors = ["#dc2626", "#16a34a", "#d97706"];
      setFill(bandColors[index] || "#6366f1");
      doc.roundedRect(margin, y, 6, cardH, 2, 2, "F");

      setFill(bandColors[index] || "#6366f1");
      doc.roundedRect(margin + 10, y + 4, 28, 9, 2, 2, "F");
      doc.setFontSize(8);
      doc.setFont("helvetica", "bold");
      setFont("#ffffff");
      doc.text(prize.price.toUpperCase(), margin + 24, y + 10, {
        align: "center",
      });

      const nameLines = doc.splitTextToSize(prize.name, contentW - 65);
      doc.setFontSize(11);
      doc.setFont("helvetica", "bold");
      setFont("#1e293b");
      doc.text(nameLines, margin + 42, y + 8);

      setDraw("#e2e8f0");
      doc.setLineWidth(0.3);
      doc.line(margin + 10, y + 16, pageW - margin - 10, y + 16);

      doc.setFontSize(8);
      doc.setFont("helvetica", "normal");
      setFont("#64748b");
      doc.text("NÚMERO GANADOR:", margin + 10, y + 23);

      doc.setFontSize(14);
      doc.setFont("helvetica", "bold");
      setFont(hasWinner ? "#16a34a" : "#d97706");
      doc.text(prize.winnerId || "PENDIENTE", margin + 52, y + 24);

      doc.setFontSize(9);
      doc.setFont("helvetica", "bold");
      setFont(hasWinner ? "#16a34a" : "#d97706");
      doc.text(
        hasWinner ? "GANADOR" : "⏳ EN ESPERA",
        pageW - margin - 5,
        y + 24,
        { align: "right" },
      );

      y += cardH + 6;
    });

    // ─── RESUMEN ────────────────────────────────────────────────
    if (y + summaryH > pageH - 30) {
      doc.addPage();
      currentPage += 1;
      drawHeader(currentPage);
      y = 80;

      doc.setFontSize(13);
      doc.setFont("helvetica", "bold");
      setFont("#1e3a6e");
      doc.text("RESULTADOS DEL SORTEO", margin, 70);

      setDraw("#f59e0b");
      doc.setLineWidth(0.8);
      doc.line(margin, 73, pageW - margin, 73);
    }

    const totalAsignados = prizesData.filter((p) => p.winnerId).length;

    setFill("#1e3a6e");
    doc.roundedRect(margin, y + 6, contentW, summaryH, 4, 4, "F");

    doc.setFontSize(10);
    doc.setFont("helvetica", "bold");
    setFont("#ffffff");
    doc.text(
      `Premios asignados: ${totalAsignados} / ${prizesData.length}`,
      margin + 8,
      y + 15,
    );

    const pct = Math.round((totalAsignados / prizesData.length) * 100);
    doc.text(`Progreso del sorteo: ${pct}%`, margin + 8, y + 23);

    setFill("#334155");
    doc.roundedRect(pageW / 2, y + 14, 60, 5, 2, 2, "F");
    if (pct > 0) {
      setFill("#f59e0b");
      doc.roundedRect(pageW / 2, y + 14, 60 * (pct / 100), 5, 2, 2, "F");
    }

    drawFooter();

    doc.save(`ganadores-rifa_${new Date().toLocaleDateString("es-GT")}.pdf`);
  };

  // ============================================
  // RENDER
  // ============================================

  return (
    <>
      <div className="relative min-h-screen overflow-hidden bg-gradient-to-r from-cyan-500 via-blue-600 to-purple-700 flex items-center justify-center">
        {/* ============================================ */}
        {/* PELOTAS — solo visibles al sortear */}
        {/* ============================================ */}

        {showBalls && (
          <div className="absolute inset-0 overflow-hidden pointer-events-none">
            {balls.map((ball) => (
              <div
                key={ball.id}
                className={`absolute rounded-full opacity-40 flex items-center justify-center text-white font-black shadow-2xl ${ball.color}`}
                style={{
                  left: `${ball.left}%`,
                  top: `${ball.startY}vh`,
                  width: `${ball.size}px`,
                  height: `${ball.size}px`,
                  animation: `airBlast ${ball.duration * ballsSpeedMultiplier}s ease-in-out infinite`,
                  animationDelay: `${ball.delay}s`,
                  "--drift-x": `${ball.driftX}px`,
                  "--drift-y": `${ball.driftY}vh`,
                }}
              >
                <span style={{ fontSize: `${ball.size / 4}px` }}>
                  {ball.number}
                </span>
              </div>
            ))}
          </div>
        )}

        {/* ============================================ */}
        {/* LOGO */}
        {/* ============================================ */}

        <div className="absolute top-0 left-0 z-20">
          <img src={Logo} className="h-50" alt="logo" />
        </div>

        {/* ============================================ */}
        {/* CARD */}
        {/* ============================================ */}

        <div className="relative z-10 bg-white/10 backdrop-blur-lg border border-white/20 rounded-3xl shadow-2xl p-10 w-[700px] flex flex-col items-center">
          <h1 className="text-6xl font-black text-yellow-300 animate-pulse tracking-widest drop-shadow-[0_0_25px_rgba(255,255,0,1)]">
            GRAN RIFA
          </h1>

          <p className="text-3xl text-white font-bold mt-3 animate-bounce">
            🎉 Desarrollando la obra misionera 🎉
          </p>

          <div className="mt-10 bg-white rounded-3xl overflow-hidden shadow-2xl w-full">
            <img
              src={currentPrize.image}
              alt={currentPrize.name}
              className="w-full h-80 object-contain bg-white"
            />

            <div className="p-6">
              <h2 className="text-3xl font-black text-center text-gray-800">
                {currentPrize.name}
              </h2>

              {/* NUMERO GANADOR */}

              <div className="mt-6 bg-gradient-to-r from-yellow-300 via-red-500 to-pink-500 rounded-3xl p-6 shadow-2xl animate-pulse border-4 border-white">
                <div className="text-center text-white text-lg font-bold">
                  NUMERO GANADOR
                </div>
                <div className="flex justify-center gap-3 min-h-[90px] items-center">
                  {(animatedWinnerId || currentPrize.winnerId || "")
                    .split("")
                    .map((digit, i) => (
                      <div
                        key={i}
                        className="w-14 h-14 rounded-full flex items-center justify-center font-black text-2xl shadow-2xl border-4 border-white"
                        style={{
                          background:
                            digit === "-"
                              ? "rgba(255,255,255,0.2)"
                              : `radial-gradient(circle at 35% 35%, #ffffff55, transparent 60%),
               radial-gradient(circle at 65% 65%, #00000033, transparent 50%),
               ${["#e53e3e", "#d69e2e", "#3182ce", "#38a169", "#805ad5"][i % 5]}`,
                          boxShadow:
                            digit === "-"
                              ? "none"
                              : "0 6px 20px rgba(0,0,0,0.4), inset 0 -3px 6px rgba(0,0,0,0.3), inset 0 3px 6px rgba(255,255,255,0.3)",
                        }}
                      >
                        <span className="text-white drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)]">
                          {digit}
                        </span>
                      </div>
                    ))}
                </div>
              </div>

              <div className="mt-5 text-center text-2xl font-black text-gray-700">
                {currentPrize.price}
              </div>

              {/* BOTON */}

              <button
                onClick={assignWinner}
                disabled={isLoading || (currentPrize.attemptsLeft ?? 3) <= 0}
                className={`w-full mt-8 text-white text-2xl font-black py-5 rounded-2xl transition-all duration-300 shadow-2xl
                  ${
                    (currentPrize.attemptsLeft ?? 3) <= 0
                      ? "bg-gray-500 cursor-not-allowed"
                      : `${currentPrize.buttonBg} ${currentPrize.buttonHover} hover:scale-105`
                  }`}
              >
                {isLoading ? (
                  "🎲 SORTEANDO..."
                ) : (currentPrize.attemptsLeft ?? 3) <= 0 ? (
                  "❌ INTENTOS AGOTADOS"
                ) : currentPrize.winnerId ? (
                  "🔁 REASIGNAR GANADOR"
                ) : (
                  "🎯 ASIGNAR GANADOR"
                )}
              </button>

              {/* Indicador de intentos */}
              <div className="mt-3 text-center text-sm text-gray-700">
                Intentos restantes: {currentPrize.attemptsLeft ?? 3}
              </div>
            </div>
          </div>

          {/* BOTONES DE NAVEGACION */}

          <div className="flex gap-4 mt-8 flex-wrap justify-center">
            <button
              onClick={handlePrevious}
              className="bg-gray-700 hover:bg-gray-800 text-white font-bold px-6 py-3 rounded-xl shadow-xl"
            >
              ⬅ Anterior
            </button>

            <button
              onClick={handleNext}
              className="bg-blue-600 hover:bg-blue-700 text-white font-bold px-6 py-3 rounded-xl shadow-xl"
            >
              Siguiente ➡
            </button>

            <button
              onClick={resetAllWinners}
              className="bg-red-600 hover:bg-red-700 text-white font-bold px-6 py-3 rounded-xl shadow-xl"
            >
              Reiniciar
            </button>

            <button
              onClick={() => setShowWinnersFloatingList((prev) => !prev)}
              className="bg-yellow-400 hover:bg-yellow-500 text-black font-black px-6 py-3 rounded-xl shadow-xl"
            >
              🏆 Ver Ganadores
            </button>

            <button
              onClick={generatePDF}
              className="bg-green-600 hover:bg-green-700 text-white font-black px-6 py-3 rounded-xl shadow-xl"
            >
              📄 Descargar PDF
            </button>
          </div>
        </div>

        {/* ============================================ */}
        {/* PANEL GANADORES */}
        {/* ============================================ */}

        {showWinnersFloatingList && (
          <div className="fixed right-5 top-5 z-50 bg-white rounded-3xl shadow-2xl p-5 w-[450px] max-h-[85vh] overflow-y-auto">
            <h2 className="text-3xl font-black text-center mb-5">
              🎉 GANADORES 🎉
            </h2>

            {prizesData.map((prize) => (
              <div
                key={prize.id}
                className="flex items-center gap-3 mb-4 bg-gray-100 p-3 rounded-2xl"
              >
                <img
                  src={prize.image}
                  alt={prize.name}
                  className="w-16 h-16 object-cover rounded-xl"
                />
                <div>
                  <div className="font-black text-lg">{prize.price}</div>
                  <div className="text-red-600 font-black text-xl">
                    {prize.winnerId || "Pendiente"}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* FOOTER */}

        <div className="fixed bottom-0 left-0 w-full bg-black/80 backdrop-blur-md text-white text-center p-4 z-50">
          <p className="font-black text-red-500 text-xl">
            Ministerios el Calvario
          </p>
          <p className="text-lg">
            PBX:
            <a href="tel:+50222468080" className="text-blue-400 ml-2">
              (502) 2246-8080
            </a>
          </p>
        </div>
      </div>

      {/* ============================================ */}
      {/* ANIMACIONES */}
      {/* ============================================ */}

      <style>{`
        @keyframes airBlast {
          0% {
            transform: translate(0px, 0vh) rotate(0deg) scale(1);
          }
          15% {
            transform: translate(calc(var(--drift-x) * 0.3), calc(var(--drift-y) * 0.4)) rotate(90deg) scale(1.05);
          }
          30% {
            transform: translate(calc(var(--drift-x) * -0.5), calc(var(--drift-y) * 0.7)) rotate(200deg) scale(0.95);
          }
          50% {
            transform: translate(calc(var(--drift-x) * 0.8), calc(var(--drift-y) * 1)) rotate(360deg) scale(1.1);
          }
          65% {
            transform: translate(calc(var(--drift-x) * -0.3), calc(var(--drift-y) * 0.6)) rotate(450deg) scale(0.9);
          }
          80% {
            transform: translate(calc(var(--drift-x) * 0.6), calc(var(--drift-y) * 0.3)) rotate(600deg) scale(1.05);
          }
          100% {
            transform: translate(0px, 0vh) rotate(720deg) scale(1);
          }
        }
      `}</style>
    </>
  );
}

export default App;
